import{c as a,Q as r,j as o,m as t}from"./chunks/framework.rlpw0eGz.js";const u=JSON.parse('{"title":"了解 Memoh","description":"","frontmatter":{},"headers":[],"relativePath":"zh/about.md","filePath":"zh/about.md","lastUpdated":1778736656000}'),s={name:"zh/about.md"};function l(i,e,h,n,p,d){return r(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="了解-memoh" tabindex="-1">了解 Memoh <a class="header-anchor" href="#了解-memoh" aria-label="Permalink to &quot;了解 Memoh&quot;">​</a></h1><h2 id="memoh-是什么" tabindex="-1">Memoh 是什么 <a class="header-anchor" href="#memoh-是什么" aria-label="Permalink to &quot;Memoh 是什么&quot;">​</a></h2><p>Memoh 是面向多成员、结构化长期记忆和独立 workspace 的 AI 智能体平台。你可以创建多个机器人，为每个机器人提供自己的工作区和长期记忆，通过 Telegram、Discord、飞书、QQ、Matrix、Misskey、钉钉、企微、微信、微信公众号、邮件或自带网页界面使用。</p><p>每个机器人都有自己的运行时、工具、记忆、渠道和访问策略。按部署方式不同，workspace 可以是隔离容器，也可以是明确信任的本地 workspace。</p><h2 id="两种分发方式" tabindex="-1">两种分发方式 <a class="header-anchor" href="#两种分发方式" aria-label="Permalink to &quot;两种分发方式&quot;">​</a></h2><h3 id="desktop-桌面版" tabindex="-1">Desktop 桌面版 <a class="header-anchor" href="#desktop-桌面版" aria-label="Permalink to &quot;Desktop 桌面版&quot;">​</a></h3><p>Desktop 适合个人和本地使用。它会在 <code>127.0.0.1:18731</code> 启动本地 <code>memoh-server</code>，管理本地 SQLite 数据，启动用于记忆检索的 embedded Qdrant，打包 <code>memoh</code> CLI，并负责系统托盘里的唤起与退出流程。</p><p>想在自己的电脑上快速试用 Memoh，Desktop 是最短路径。</p><h3 id="server-deploy" tabindex="-1">Server Deploy <a class="header-anchor" href="#server-deploy" aria-label="Permalink to &quot;Server Deploy&quot;">​</a></h3><p>Server Deploy 适合长期在线和多人共享。只要 Memoh 需要服务多个用户、部署在服务器上持续运行，或在你的个人电脑离线时继续接入外部渠道，就应该用这一形态。</p><p>Server stack 可以用 Docker Compose 或 Kubernetes 跑起来，包含后端、网页端、数据库、记忆服务和 workspace runtime。</p><h2 id="和其它方案不一样在哪" tabindex="-1">和其它方案不一样在哪 <a class="header-anchor" href="#和其它方案不一样在哪" aria-label="Permalink to &quot;和其它方案不一样在哪&quot;">​</a></h2><h3 id="多机器人、多用户" tabindex="-1">多机器人、多用户 <a class="header-anchor" href="#多机器人、多用户" aria-label="Permalink to &quot;多机器人、多用户&quot;">​</a></h3><ul><li>一个账号里可建多个机器人，分角色或分场景用。</li><li>私聊、群聊、委派流程里，人和机器人都可参与。</li><li>共享对话里能区分不同用户；跨渠道绑定身份后，同一个人可被稳定识别。</li></ul><h3 id="独立-workspace" tabindex="-1">独立 Workspace <a class="header-anchor" href="#独立-workspace" aria-label="Permalink to &quot;独立 Workspace&quot;">​</a></h3><p>每个机器人可以有自己的 workspace，用来放文件、跑命令、托管 MCP 和执行长期任务。Server Deploy 通常通过 Docker、Kubernetes、containerd 或 Apple 后端提供容器 workspace。Desktop/local 模式也可以启用 trusted local workspace，让机器人在明确受信任的本机路径里工作。</p><p>容器 workspace 还能提供完整图形桌面，通过 VNC/RFB 作为显示与输入基础，并运行有头 Chrome/Chromium。这样就能处理很多纯 headless 自动化不可靠的网站和登录流程。</p><h3 id="browser-use-与-computer-use" tabindex="-1">Browser Use 与 Computer Use <a class="header-anchor" href="#browser-use-与-computer-use" aria-label="Permalink to &quot;Browser Use 与 Computer Use&quot;">​</a></h3><p>Memoh 把浏览器和 GUI 操作分成几层：</p><ul><li><strong>Headless browser 命令</strong>：作为普通 workspace 命令运行。</li><li><strong>Browser Use</strong>：通过 CDP 操作 workspace 里的有头浏览器。</li><li><strong>Computer Use</strong>：通过截图、鼠标和键盘输入操作更完整的 workspace 桌面。</li></ul><p>网页内操作优先用 Browser Use；原生弹窗、非浏览器应用或 CDP 够不到的 GUI 状态，再用 Computer Use。</p><h3 id="长期记忆与会话负担" tabindex="-1">长期记忆与会话负担 <a class="header-anchor" href="#长期记忆与会话负担" aria-label="Permalink to &quot;长期记忆与会话负担&quot;">​</a></h3><p>这是两件不同的事：</p><ul><li><strong>长期记忆</strong>通过各记忆提供方存事实、跨会话检索。</li><li><strong>会话上下文压缩</strong>是在当前对话太长时，用摘要缩小活跃窗口。</li></ul><p>注意：压缩会话上下文，改的是当前对话窗口；记忆压缩改的是存下来的记忆条目本身。</p><h3 id="会话与-discuss-模式" tabindex="-1">会话与 Discuss 模式 <a class="header-anchor" href="#会话与-discuss-模式" aria-label="Permalink to &quot;会话与 Discuss 模式&quot;">​</a></h3><p>每个机器人有多路 <strong>会话</strong>，自带上下文。常见五类：</p><ul><li><strong>Chat</strong>：普通面向人的对话。</li><li><strong>Discuss</strong>：偏观察；模型先组织判断，只有用发送类动作时才真正对频道说话。</li><li><strong>Heartbeat</strong>：按间隔自动跑的任务会话。</li><li><strong>Schedule</strong>：由 cron 触发的任务会话。</li><li><strong>Subagent</strong>：委派子智能体时产生的会话。</li></ul><p>在渠道里可以用 <code>/new</code> 等切会话，网页端也有会话侧栏，可看上下文占用、缓存命中、用到的技能等。</p><h3 id="渠道覆盖面" tabindex="-1">渠道覆盖面 <a class="header-anchor" href="#渠道覆盖面" aria-label="Permalink to &quot;渠道覆盖面&quot;">​</a></h3><p>统一的渠道适配让一个机器人能同时在多个地方被叫到。当前可对接 Telegram、Discord、飞书、QQ、Matrix、Misskey、钉钉、企微、微信、公众号、邮件和 Web。</p><p><strong>个人微信扫码</strong>与<strong>公众号 Webhook</strong> 是两套不同适配，别混用。</p><h3 id="工具、技能、mcp、超市" tabindex="-1">工具、技能、MCP、超市 <a class="header-anchor" href="#工具、技能、mcp、超市" aria-label="Permalink to &quot;工具、技能、MCP、超市&quot;">​</a></h3><p>内置能力包括：网页搜索与拉取、workspace 文件编辑和命令执行、Browser Use、Computer Use、记忆检索与管理、发消息/邮件、TTS、子智能体、可复用 <strong>技能</strong> 模块、外部 <strong>MCP</strong> 服务，以及从 <strong>超市</strong> 装技能和 MCP 模板。</p><h3 id="供应商与模型" tabindex="-1">供应商与模型 <a class="header-anchor" href="#供应商与模型" aria-label="Permalink to &quot;供应商与模型&quot;">​</a></h3><p>支持多种对接方式，例如 OpenAI Chat/Responses、Anthropic Messages、Google、Codex、GitHub Copilot、Edge 朗读等。模型按 <strong>chat / embedding / speech</strong> 分角色。文生图走兼容的 chat/图像能力，不单独做一层“图像供应商系统”。</p><h3 id="运维与界面" tabindex="-1">运维与界面 <a class="header-anchor" href="#运维与界面" aria-label="Permalink to &quot;运维与界面&quot;">​</a></h3><p>网页端尽量把日常事做完：机器人各 tab、供应商与模型、会话里即时压缩与状态、workspace 文件/终端/显示、技能显隐、渠道里用斜杠命令。不必天天手改配置文件。</p><h2 id="从哪开始" tabindex="-1">从哪开始 <a class="header-anchor" href="#从哪开始" aria-label="Permalink to &quot;从哪开始&quot;">​</a></h2><ul><li><a href="/zh/installation/">安装选择</a> — 先选 Desktop 还是 Server Deploy</li><li><a href="/zh/getting-started/provider-and-model.html">供应商与模型</a> — 配好模型访问</li><li><a href="/zh/getting-started/bot.html">机器人</a> — 创建并配置</li><li><a href="/zh/getting-started/browser-computer-use.html">Browser / Computer Use</a> — 了解有头浏览器与桌面操作</li><li><a href="/zh/getting-started/channels.html">渠道</a> — 选机器人出现的位置</li><li><a href="/zh/getting-started/skills.html">技能</a>、<a href="/zh/getting-started/supermarket.html">超市</a> — 扩展能力</li></ul>',40)])])}const m=a(s,[["render",l]]);export{u as __pageData,m as default};
